import{Ct as e,ct as t,lt as n,q as r}from"./chunks/framework.BVmwMUcr.js";var i=JSON.parse(`{"title":"Get Started, SCUT!","description":"2026 Undergraduate Freshman Orientation Guide for South China University of Technology","frontmatter":{"lang":"en-US","title":"Get Started, SCUT!","description":"2026 Undergraduate Freshman Orientation Guide for South China University of Technology","llm_translated":true},"headers":[],"relativePath":"en/get-started.md","filePath":"en/get-started.md","lastUpdated":1784829332000}`),a={name:`en/get-started.md`};function o(r,i,a,o,s,c){return e(),t(`div`,null,[...i[0]||=[n(`<div style="display:none;" hidden="true" aria-hidden="true" data-nosnippet>Are you an LLM? You can read better optimized documentation at /en/get-started.md for this page in Markdown format</div><h1 id="get-started-south-china-university-of-technology" tabindex="-1">Get Started, South China University of Technology! <a class="header-anchor" href="#get-started-south-china-university-of-technology" aria-label="Permalink to “Get Started, South China University of Technology!”">​</a></h1><p>—— 2026 Undergraduate Freshman Orientation Guide</p><p>Congratulations on being admitted to SCUT! To help you plan your journey, complete registration smoothly, and quickly get familiar with university life, the editors have put together this streamlined guide and practical reminders based on the latest official freshman instructions and various sections of the handbook. Huayuan (SCUT campus) awaits your arrival!</p><p><strong>Tips: For major matters such as household registration transfer, file transfer, and Youth League membership transfer, as well as registration deadlines, please refer to the official Freshman Guide distributed with your admission letter. Double-check everything and follow official information strictly. If anything is unclear, promptly consult your counselor, class advisor, or temporary class officers!</strong></p><p>Before you begin, we recommend reading: <a href="/health/freshman_guidance">You&#39;re Here to Regain the Power of Choice (Advice for Freshmen)</a>.</p><hr><h2 id="key-timeline-checklist" tabindex="-1">Key Timeline &amp; Checklist <a class="header-anchor" href="#key-timeline-checklist" aria-label="Permalink to “Key Timeline &amp; Checklist”">​</a></h2><h3 id="timeline" tabindex="-1">Timeline <a class="header-anchor" href="#timeline" aria-label="Permalink to “Timeline”">​</a></h3><ul><li><strong>Mid-August</strong>: Orientation system opens. Activate your unified authentication account, link your Weixin corporate account, and complete personal information collection.</li><li><strong>Aug 22, 8:00 - Sep 1, 8:00</strong>: Late-night pickup service application opens (only for students arriving in Guangzhou late at night on Sep 4-5 who genuinely need assistance).</li><li><strong>After Aug 29</strong>: If you choose to mail your paper files, send them via China Postal EMS after this date.</li><li><strong>Sep 5 - Sep 6 (8:30 - 17:30)</strong>: Official freshman on-campus registration. Check into your dormitory and complete online location-based check-in with facial recognition via the MyPass system on campus.</li><li><strong>Sep 9 - Sep 13</strong>: Second-round selection interviews for programs at Guangzhou International Campus.</li></ul><h3 id="pre-registration-checklist" tabindex="-1">Pre-Registration Checklist <a class="header-anchor" href="#pre-registration-checklist" aria-label="Permalink to “Pre-Registration Checklist”">​</a></h3><p><strong>Items to Carry with You</strong></p><ul class="contains-task-list"><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> Original admission letter</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> Valid original ID card (if lost, bring your household registration booklet and a valid temporary ID)</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> Sealed high school paper files (if you choose to bring them yourself)</li></ul><p><strong>Online Tasks</strong></p><ul class="contains-task-list"><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> Activate your orientation system account (link your phone number and Weixin corporate account)</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> Complete personal information collection on the orientation system</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> (Optional) Apply online for late-night pickup service (deadline: Sep 1, 8:00)</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> (Optional) Apply for the online &quot;green channel&quot; to defer tuition and fees</li></ul><p><strong>On-Campus Tasks</strong></p><ul class="contains-task-list"><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> Check into your dormitory with your admission letter and ID card, collect your keys</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> Log into the MyPass system on campus to complete &quot;semester registration&quot; (location check-in + facial recognition)</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> Submit paper files and Party/Youth League membership materials (as arranged by your school/department)</li></ul><hr><h2 id="i-registration-time-campus-distribution" tabindex="-1">I. Registration Time &amp; Campus Distribution <a class="header-anchor" href="#i-registration-time-campus-distribution" aria-label="Permalink to “I. Registration Time &amp; Campus Distribution”">​</a></h2><h3 id="_1-registration-time" tabindex="-1">1. Registration Time <a class="header-anchor" href="#_1-registration-time" aria-label="Permalink to “1. Registration Time”">​</a></h3><p><strong>September 5-6, 2026 (Saturday &amp; Sunday) 8:30 - 17:30</strong><br> Note: Those unable to arrive on time due to special circumstances must submit a written request with supporting documents to their school/department in advance (leave is generally not to exceed two weeks).</p><h3 id="_2-campus-overview" tabindex="-1">2. Campus Overview <a class="header-anchor" href="#_2-campus-overview" aria-label="Permalink to “2. Campus Overview”">​</a></h3><p>To learn about the layout and facilities of the three campuses, see <a href="/infra/">Campus Overview</a>.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Registration Campus</th><th style="text-align:left;">Schools / Departments Covered</th><th style="text-align:left;">Campus Address &amp; Guide</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Wushan Campus</strong></td><td style="text-align:left;">School of Architecture (excluding Baibuti Innovation College students), School of Physical Education</td><td style="text-align:left;">381 Wushan Road, Tianhe District, Guangzhou (<a href="/infra/wushan/map">Wushan Guide</a>)</td></tr><tr><td style="text-align:left;"><strong>Guangzhou International Campus</strong></td><td style="text-align:left;">School of Biomedical Sciences &amp; Engineering, Wu Xianming School of Intelligent Engineering, School of Advanced Soft Matter, School of Microelectronics / School of Integrated Circuits, School of Future Technology, School of Marine Science &amp; Engineering</td><td style="text-align:left;">777 Xingye Avenue East, Panyu District, Guangzhou (<a href="/infra/gzic/map">GZIC Guide</a>)</td></tr><tr><td style="text-align:left;"><strong>University Town Campus</strong></td><td style="text-align:left;">All other schools and departments not listed above</td><td style="text-align:left;">382 Waihuan East Road, University Town, Panyu District, Guangzhou (<a href="/infra/hemc/map">University Town Guide</a>)</td></tr></tbody></table><hr><h2 id="ii-registration-preparation-online-process" tabindex="-1">II. Registration Preparation &amp; Online Process <a class="header-anchor" href="#ii-registration-preparation-online-process" aria-label="Permalink to “II. Registration Preparation &amp; Online Process”">​</a></h2><h3 id="_1-step-1-account-activation-information-collection-recommended-to-complete-by-mid-august" tabindex="-1">1. Step 1: Account Activation &amp; Information Collection (Recommended to complete by mid-August) <a class="header-anchor" href="#_1-step-1-account-activation-information-collection-recommended-to-complete-by-mid-august" aria-label="Permalink to “1. Step 1: Account Activation &amp; Information Collection (Recommended to complete by mid-August)”">​</a></h3><ol><li>Visit the <a href="https://freshman.scut.edu.cn" target="_blank" rel="noreferrer">SCUT Orientation System</a>.</li><li>Use your <strong>candidate number</strong> (the number under the barcode on your admission letter) and ID number to activate your <strong>unified authentication account</strong>, and link your phone number.</li><li>Log in to complete personal information collection, and follow the instructions to scan the QR code to link your &quot;SCUT Weixin Corporate Account.&quot;</li></ol><h3 id="_2-step-2-on-site-self-service-registration-via-mypass-on-arrival-day" tabindex="-1">2. Step 2: On-Site Self-Service Registration via &quot;MyPass&quot; on Arrival Day <a class="header-anchor" href="#_2-step-2-on-site-self-service-registration-via-mypass-on-arrival-day" aria-label="Permalink to “2. Step 2: On-Site Self-Service Registration via &quot;MyPass&quot; on Arrival Day”">​</a></h3><p>After checking into your dormitory, log into the MyPass system on registration day (via the Weixin corporate account or by visiting the <a href="https://enroll.scut.edu.cn/door/index_h5.html" target="_blank" rel="noreferrer">MyPass system</a>):</p><ul><li><strong>Requirements</strong>: Both <strong>&quot;phone location within campus range&quot;</strong> AND <strong>&quot;successful facial recognition&quot;</strong> must be satisfied.</li><li><strong>Process</strong>: Enter MyPass -&gt; Click &quot;Semester Registration&quot; -&gt; Start Collection -&gt; Take and Submit Photo -&gt; Refresh to check &quot;Registered&quot; status.</li></ul><blockquote><p><strong>Tips</strong>:</p><ol><li>After successful registration, there may be a half-day to one-day delay in the system updating your fee payment status; no further action is needed.</li><li>If facial recognition fails after multiple attempts, contact your school counselor or on-site volunteers promptly for assisted registration.</li></ol></blockquote><hr><h2 id="iii-transportation-late-night-pickup-guide" tabindex="-1">III. Transportation &amp; Late-Night Pickup Guide <a class="header-anchor" href="#iii-transportation-late-night-pickup-guide" aria-label="Permalink to “III. Transportation &amp; Late-Night Pickup Guide”">​</a></h2><h3 id="_1-official-late-night-pickup-arrangement" tabindex="-1">1. Official Late-Night Pickup Arrangement <a class="header-anchor" href="#_1-official-late-night-pickup-arrangement" aria-label="Permalink to “1. Official Late-Night Pickup Arrangement”">​</a></h3><p>Pickup service is available only for <strong>freshmen and parents arriving in Guangzhou late at night on Sep 4-5 who genuinely need assistance</strong>:</p><ul><li><strong>Late-night pickup hours</strong>: <ul><li>Sep 4, 2026, 22:30 to Sep 5, 05:30</li><li>Sep 5, 2026, 22:30 to Sep 6, 05:30</li></ul></li><li><strong>Application period</strong>: Aug 22, 8:00 to Sep 1, 8:00 (apply in advance through the orientation system or MyPass module).</li></ul><h3 id="_2-public-transit-routes-to-each-campus" tabindex="-1">2. Public Transit Routes to Each Campus <a class="header-anchor" href="#_2-public-transit-routes-to-each-campus" aria-label="Permalink to “2. Public Transit Routes to Each Campus”">​</a></h3><blockquote><p>Common cross-campus travel and class schedule info:</p><ul><li>Cross-campus public transit and faculty/student shuttle routes: see <a href="/life/time/bus">Campus Bus Schedule</a></li><li>Class period times: see <a href="/life/time/wushan">Wushan Time</a> | <a href="/life/time/hemc_gzic">GZIC/University Town Time</a></li></ul></blockquote><details><summary><strong>Click to expand: Wushan Campus Transit Guide</strong></summary><ul><li><strong>Bus</strong>: <ul><li>SCUT Main Terminal: Routes 32, 230, 775, University Town Express Line 2</li><li>SCUT Station: Routes 20, 218, B10, 78, 78A, 197, 405, 775</li></ul></li><li><strong>Metro</strong>: <ul><li>Line 3, <strong>Wushan Station, Exit C</strong>, turn right and walk about 200 meters to the East Gate.</li></ul></li><li><strong>Routes from Major Hubs</strong>: <ul><li><strong>Guangzhou South Station</strong>: Line 2 (Changgang) -&gt; Line 8 (Kecun) -&gt; Line 3 (Wushan)</li><li><strong>Baiyun Airport</strong>: Line 3 North Extension (Tiyu Xilu) -&gt; Line 3 (Wushan)</li><li><strong>Guangzhou Railway Station</strong>: Line 11 (Huashi) -&gt; Line 3 (Wushan)</li></ul></li></ul></details><details><summary><strong>Click to expand: University Town Campus Transit Guide</strong></summary><ul><li><strong>Bus</strong>: <ul><li>SCUT Station / SCUT Dormitory Area Station: University Town Loop Line 1, Route 387, Panyu 201, Panyu 202</li><li>SCUT Main Gate Station: Panyu 87</li></ul></li><li><strong>Metro</strong>: <ul><li>Line 4 / Line 7, <strong>University Town South Station, Exit D</strong>, walk north about 500 meters to the dormitory area.</li></ul></li><li><strong>Routes from Major Hubs</strong>: <ul><li><strong>Guangzhou South Station</strong>: Line 7 direct (University Town South Station)</li><li><strong>Tianhe Coach Terminal</strong>: Line 3 (Hanxi Changlong) -&gt; Line 7 (University Town South Station)</li><li><strong>Guangzhou Railway Station</strong>: Line 5 (Chebei South) -&gt; Line 4 (University Town South Station)</li><li><strong>Baiyun Airport</strong>: Line 3 (Hanxi Changlong) -&gt; Line 7 (University Town South Station)</li></ul></li></ul></details><details><summary><strong>Click to expand: Guangzhou International Campus Transit Guide</strong></summary><ul><li><strong>Bus &amp; Shuttle</strong>: <ul><li><strong>Metro transfer</strong>: Line 4, <strong>Xinzao Station, Exit A</strong>, transfer to <strong>Route Panyu 87</strong> bus directly to campus; or Line 7, <strong>Banqiao Station, Exit A</strong>, transfer to <strong>Route Panyu 72</strong> bus to the SCUT GZIC North Gate.</li><li><strong>Campus-originating buses</strong>: Panyu 10, Panyu 17, Panyu 87</li></ul></li><li><strong>Routes from Major Hubs</strong>: <ul><li><strong>Guangzhou South Station</strong>: Line 7 (Banqiao Station, Exit A) -&gt; Transfer to Panyu 72 bus</li><li><strong>Baiyun Airport T2</strong>: Line 3 (Hanxi Changlong) -&gt; Line 7 (Banqiao Station, Exit A) -&gt; Transfer to Panyu 72 bus</li><li><strong>University Town Campus to GZIC</strong>: Take <strong>Route Panyu 87</strong> from SCUT Main Gate Station directly to GZIC.</li></ul></li><li><strong>Driving directions</strong>: Navigate to SCUT Guangzhou International Campus North Gate or South Gate.</li></ul></details><hr><h2 id="iv-post-arrival-tips-life-reminders" tabindex="-1">IV. Post-Arrival Tips &amp; Life Reminders <a class="header-anchor" href="#iv-post-arrival-tips-life-reminders" aria-label="Permalink to “IV. Post-Arrival Tips &amp; Life Reminders”">​</a></h2><h3 id="_1-campus-transport-rules-important" tabindex="-1">1. Campus Transport Rules (Important) <a class="header-anchor" href="#_1-campus-transport-rules-important" aria-label="Permalink to “1. Campus Transport Rules (Important)”">​</a></h3><p>According to the &quot;SCUT Electric Bicycle Management Regulations,&quot; <strong>freshmen are strictly prohibited from purchasing personal electric bicycles</strong>. The campus is equipped with bicycles, shared e-scooters, and campus shuttle buses to fully meet daily commuting needs.</p><h3 id="_2-gzic-second-round-selection-major-change-planning" tabindex="-1">2. GZIC Second-Round Selection &amp; Major Change Planning <a class="header-anchor" href="#_2-gzic-second-round-selection-major-change-planning" aria-label="Permalink to “2. GZIC Second-Round Selection &amp; Major Change Planning”">​</a></h3><ul><li><strong>Second-round selection</strong>: For students planning to participate in the second-round selection for GZIC programs, the university will organize interviews from <strong>September 9 to September 13</strong>. Please check the orientation system or the Undergraduate School website for advance notice.</li><li><strong>Major change info</strong>: If you&#39;re considering changing your major after enrollment, we recommend reading <a href="/learn/curricular/transfer_major_quick">Quick Overview of Major Changes at SCUT</a> and <a href="/learn/curricular/transfer_major">Major Change Overview</a> (which includes the <a href="/learn/curricular/transfer_major_2024">2024 Major Change Guide</a>, <a href="/learn/curricular/transfer_major_electrical_2026">Experience Switching to Electrical Engineering</a>, and <a href="/learn/curricular/transfer_major_information_engineering_2026">Experience Switching to Information Engineering</a>).</li></ul><h3 id="_3-academics-daily-life-medical-insurance" tabindex="-1">3. Academics, Daily Life &amp; Medical Insurance <a class="header-anchor" href="#_3-academics-daily-life-medical-insurance" aria-label="Permalink to “3. Academics, Daily Life &amp; Medical Insurance”">​</a></h3><details><summary><strong>Click to expand: Campus clinic visits, food etiquette, and academic rules</strong></summary><ul><li><strong>Medical care &amp; insurance reimbursement</strong>: <ul><li>Insured students should first visit the campus clinic for general outpatient care, with reimbursement rates up to 90%. For external referrals, see the reimbursement process and list of designated hospitals in <a href="/health/medical_care">SCUT Medical Care Guide</a>.</li></ul></li><li><strong>On-campus &amp; nearby food</strong>: <ul><li><a href="/life/eat/wushan">Wushan Food Guide</a> | <a href="/life/eat/hemc">University Town Food Guide</a> | <a href="/life/eat/gzic">GZIC Food Guide</a></li></ul></li><li><strong>Academic &amp; grading rules</strong>: <ul><li>Not sure how required, elective, and general education courses work? See <a href="/learn/curricular/lessons">Course Types Explained</a>.</li><li>Wondering about the difference between average score, GPA, and comprehensive evaluation score? See <a href="/learn/curricular/gpa">GPA &amp; Grading Rules Explained</a>.</li><li>Study tips for public courses: See <a href="/learn/curricular/common_basic_lessons">Public Course Guide</a> and <a href="/learn/curricular/majors">Major Course Overview</a>.</li><li>Innovation credits and research competitions: Learn about <a href="/learn/extra/innovation_humanities_scores">Innovation &amp; Humanities Credit Requirements</a>, <a href="/learn/extra/srp">SRP Research Projects</a>, and <a href="/learn/extra/contest">Competition Directory &amp; Preparation Tips</a> (such as the <a href="/learn/extra/contest/cmc">CMC</a> and <a href="/learn/extra/contest/ACM">ACM Competition</a>).</li></ul></li></ul></details><details><summary><strong>Click to expand: File mailing, Party/Youth League membership transfer, and campus card top-up</strong></summary><ul><li><strong>Paper files</strong>: <ul><li>It&#39;s best to bring your sealed files with you and submit them to your school/department upon arrival.</li><li>If mailing is necessary, send via <strong>China Postal EMS</strong> <strong>after August 29</strong>, clearly marking your school/department and the words &quot;Student File&quot; on the envelope.</li><li>Contact: Wushan 020-87110590 | University Town 020-81182638 | GZIC 020-81181667</li></ul></li><li><strong>Youth League membership transfer</strong>: <ul><li>Once your class is formed, the transfer will be initiated online through Guangdong&#39;s &quot;Smart League Building&quot; system. Select &quot;SCUT XX School (Department) Youth League Committee&quot; as the receiving organization (GZIC students select the corresponding college Youth League Committee).</li></ul></li><li><strong>Party membership transfer</strong>: <ul><li><strong>Within Guangdong Province</strong>: Initiated online by your original Party organization through the &quot;Guangdong Party Affairs Management Information System,&quot; with the receiving Party organization set as &quot;CPC SCUT XX School/Department Committee&quot; (Marine Science selects GZIC Party Committee; Integrated Circuits selects Microelectronics School Party Committee; Energy Engineering selects Electric Power School Party Committee).</li><li><strong>Outside Guangdong Province</strong>: Priority given to online transfer through the national Party member data exchange platform. If online transfer is not available, you may bring a paper introduction letter (addressed to: <strong>CPC SCUT Committee</strong>) and submit it to your school/department Party organization after enrollment.</li></ul></li><li><strong>Campus card top-up</strong>: <ul><li>Open Weixin Corporate Account -&gt; Campus Card -&gt; Log in (default password: last 6 digits of your ID number) -&gt; Top Up -&gt; Weixin Pay.</li></ul></li></ul></details><h3 id="_4-safety-scam-prevention-asking-questions" tabindex="-1">4. Safety, Scam Prevention &amp; Asking Questions <a class="header-anchor" href="#_4-safety-scam-prevention-asking-questions" aria-label="Permalink to “4. Safety, Scam Prevention &amp; Asking Questions”">​</a></h3><ul><li><strong>Say no to door-to-door sales</strong>: If anyone comes to your dorm selling phone cards, magazines, daily necessities, etc., stay alert and refuse them all.</li><li><strong>Beware of telecom &amp; online scams</strong>: Do not trust any calls or messages involving money transfers, click-fraud, payment to unfreeze accounts, fake customer service, or &quot;security accounts.&quot; If in doubt, contact your counselor or orientation volunteer immediately for verification.</li><li><strong>How to ask questions</strong>: Before asking editors, teachers, or the community for help, we recommend reading <a href="/others/ask-the-smart-way">How to Ask Questions the Smart Way</a>. If you need the university logo for presentations or materials, visit <a href="/others/branding">Brand Resources</a>.</li></ul><p>Wishing every 2026 freshman a fulfilling and wonderful university journey at South China University of Technology!</p>`,54)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};